args.sparql:
SELECT ?countyLabel WHERE {
  ?match wdt:P857 "2-29 to 2-20" ;
         wdt:P585 ?year ;
         wdt:P127 wd:Q557827 .
  wd:Q3579523 wdt:P58 ?year ;
              wdt:P1343 ?player .
  ?player wdt:P18 ?team ;
          ?team wdt:P17 ?county .
  ?county rdfs:label ?countyLabel .
  FILTER (lang(?countyLabel) = "en")
}

SELECT DISTINCT ?countyLabel WHERE {
  ?match wdt:P857 "2-29 to 2-20" ;
         wdt:P585 ?year .
  ?player wdt:P1343 wd:Q3579523 ;
